mapper.select:

where 1 = 1
and alert_no like concat('%', #{alertNo}, '%')
and proj_id = #{projId}
and proj_name like concat('%', #{projName}, '%')
and rule_type = #{ruleType}
and alert_level = #{alertLevel}
and status = #{status}
and create_time >= concat(#{beginTime}, ' 00:00:00')
and create_time <= concat(#{endTime}, ' 23:59:59')
order by case alert_level when '3' then 1 when '2' then 2 when '1' then 3 else 4 end,
         case status when '0' then 1 when '3' then 2 when '1' then 3 when '2' then 4 else 5 end,
         create_time desc, alert_id desc

select count(1)
from proj_alert_record
where rule_id = #{ruleId}
  and proj_id = #{projId}
  and create_time >= date_sub(now(), interval #{hours} hour)
